SELECT cm.no, cm.title, c.name AS name, cm.hit, cm.insert_date, cm.good FROM community cm, customer c WHERE cm.customer_no = c.no

	AND category_no = #{no}

AND status = 0 ORDER BY cm.no DESC

SELECT cm.category_no, cm.no, cm.title, cm.insert_date, c.name AS name FROM community cm, customer c
WHERE cm.customer_no = c.no

	AND category_no like #{no}


	AND content like #{content}


	AND title like #{content}

AND status = 0 ORDER BY cm.no DESC
